import heapq

class Solution:
    def findKthLargest(self, nums, k):
        heap = []
        for v in nums:
            heapq.heappush(heap, v)
            if len(heap) > k:
                heapq.heappop(heap)
        return heap[0]

solutions.javascript:
var findKthLargest = function(nums, k) {
    // size-k min-heap implemented as an array
    const heap = [];
    const up = (i) => {
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p] <= heap[i]) break;
            [heap[p], heap[i]] = [heap[i], heap[p]];
            i = p;
        }
    };
    const down = (i) => {
        const n = heap.length;
        while (true) {
            let s = i, l = 2 * i + 1, r = 2 * i + 2;
            if (l < n && heap[l] < heap[s]) s = l;
            if (r < n && heap[r] < heap[s]) s = r;
            if (s === i) break;
            [heap[s], heap[i]] = [heap[i], heap[s]];
            i = s;
        }
    };
    for (const v of nums) {
        heap.push(v);
        up(heap.length - 1);
        if (heap.length > k) {
            heap[0] = heap[heap.length - 1];
            heap.pop();
            down(0);
        }
    }
    return heap[0];
};
